var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"크라켄이 선체를 붙잡았어!","JPN":"船がクラーケンに捕まった！","ENG":"Kraken's got a grip on the hull!","TWN":"克拉肯抓住船身了！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아무래도 단단히 열 받았나 본데?","JPN":"どうやら相当ムカついたようね。","ENG":"Looks like it's really mad now.","TWN":"看來是徹底惹怒它了？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"초, 촉수가 우리를 내려찍으려고 해요!","JPN":"しょ、触手がこっちを叩きつけようとしています！","ENG":"Th-the tentacle's about to smash us!","TWN":"觸、觸手要砸下來了！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐, 저거 단번에 잘라낼 수 있어요?!","JPN":"ソーニャ、一気に斬り落とせないですか！？","ENG":"Sonya, can you cut that in one swing?!","TWN":"索妮雅，妳能一次砍斷那條觸手嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"저건 무리야.","JPN":"あれは無理だ。","ENG":"No chance.","TWN":"不可能。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"날아오는 속도가 너무 빨라서 뭘 해보기도 전에 내 팔이 날아갈걸.","JPN":"触手が速すぎて、こっちが動きを取る前にあたしの腕が飛ぶ。","ENG":"It's moving too fast. I'd lose an arm before I even tried anything.","TWN":"它的觸手太快了，還沒出手我的手就先斷了！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"예전에도 다 같이 협공해서 촉수를 벨 수 있었던 거, 잊었어?","JPN":"忘れたのか？　前もみんなで協力してやっと斬れたってこと。","ENG":"Did you forget? Last time we only managed to cut one by ganging up on it.","TWN":"之前是因為幾個人合力才能一起砍掉那些觸手，妳忘了嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그러면 어떡해요!","JPN":"じゃあどうすればいいんですか！","ENG":"Then what do we do?!","TWN":"那現在怎麼辦？！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"우앙! 죽기 싫어!","JPN":"わーん！　死にたくない！","ENG":"Wahh! I don't wanna die!","TWN":"嗚哇啊啊！我不想死！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"촉수가… 반으로 갈라졌어……?","JPN":"触手が……真っ二つになった……？","ENG":"The tentacle... got sliced in half...?","TWN":"觸手……斷成兩半了……？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그 무식한 대포보다는 우아한 검술이 더 낫다고 했잖니.","JPN":"だからそのゴツい大砲なんかより、優雅な剣術のほうがましだって言ったのに。","ENG":"I told you refined swordmanship beats that brutish cannon of yours.","TWN":"我不是說過優雅的劍術比笨重的大砲好多了嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"지금 저 식칼로 크라켄 촉수를 잘라버린 거야?","JPN":"あの包丁で、クラーケンの触手を斬ったのか……？","ENG":"You cut Kraken's tentacle with that kitchen knife?","TWN":"剛剛是用那把像菜刀的短劍斬斷觸手的嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"니네 엄마… 엄청 무서운 사람이구나…….","JPN":"タリーのお母さんって……すごく怖い人だったんだな……","ENG":"Your mom... is terrifying...","TWN":"妳媽媽……好可怕……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"세리나도 그렇고, 크레데레도 그렇고… 왜 나한테서 검술을 배우려 하지 않는지…….","JPN":"セリーナもクレデレも……どうして私から剣術を教わろうとしないのかしら……","ENG":"Serina, Credere... None of them ever wanted to learn how to wield a sword from me...","TWN":"瑟琳娜和克蕾妲莉也是……為什麼沒有叫我學劍術啊……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"분명 자기 밥벌이는 확실히 할 수 있다고 그렇게 말했건만…….","JPN":"食べていくのに絶対役立つからって、あれほど言い聞かせたのに……","ENG":"Even though I told them they'd always be able to fend for themselves...","TWN":"明明說過可以養活自己……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"누구나 어머니의 검술 훈련을 받으면 질려서 도망칠걸요.","JPN":"お母様に剣術の稽古を受けたら、誰でも怖がって逃げ出しますよ。","ENG":"Anyone would run away after one round of your training, Mother.","TWN":"但只要是接受過我母親劍術訓練的人，都被操到受不了逃跑呢。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후훗, 미안한 말이지만 탈리.","JPN":"ふふっ。タリー、悪いけど……","ENG":"Fufu. I'm sorry to say this, Tallie.","TWN":"呵呵，抱歉喔，塔莉。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그런 말은 나약한 사냥감이나 지껄이는 말이란다.","JPN":"そういうセリフは軟弱な獲物が言うことよ。","ENG":"But talk like that is what weak prey tend to squeal.","TWN":"只有軟弱的獵物才會說出這種話呢。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"히,히이익!죄송해요죄송해요죄송해요죄송해요!!","JPN":"ひ、ひいいっ！　ごめんなさいごめんなさいごめんなさいごめんなさい！！","ENG":"E-eek! I'm sorry, I'm sorry, I'm sorry!!","TWN":"呃、嗚哇啊！對不起對不起對不起對不起！！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"선체를 붙잡고 있는 촉수들이 너무 많아.","JPN":"船体を掴んでいる触手が多すぎる。","ENG":"There are too many tentacles clinging to the hull.","TWN":"抓住船身的觸手太多了……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"이대로 있다간 배 째로 바다에 끌려들어가겠어.","JPN":"このままだと、船ごと海の中に引きずり込まれちゃう。","ENG":"If this keeps up, the whole ship's gonna get dragged under.","TWN":"再這樣下去，整艘船都會被拖進海裡。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"선장님! 크라켄이 함선을 붙잡았습니다!","JPN":"船長！　艦船がクラーケンに捕まりました！","ENG":"Captain! Kraken has grabbed the ship!","TWN":"船長！克拉肯抓住我們的艦船了！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"크라켄으로부터 강한 열원 발생 확인!","JPN":"クラーケンから高熱源反応を確認！","ENG":"Detecting an intense heat source from Kraken!","TWN":"我們偵測到克拉肯身上正在釋放強烈的熱源！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"이대로라면 함선은 통째로 녹아버릴 거예요!","JPN":"このままでは艦船ごと溶けてしまいます！","ENG":"At this rate, the ship will melt!","TWN":"再這樣下去，整艘船會融化的！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"아무래도 내가 나서야겠구나.","JPN":"どうやら私の出番のようね。","ENG":"Looks like it's my turn.","TWN":"看來還是得由我上場了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L1_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"저 촉수라면 이미 여러 번 베어봤단다.","JPN":"あの触手なら何度も切ったことがあるわ。","ENG":"I've cut those tentacles plenty of times already.","TWN":"我已經砍過那種觸手好幾次。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"내가 촉수를 잘라 틈을 벌린 사이에 놈의 공격에서 벗어나렴.","JPN":"私が触手を切るから、その隙にやつの攻撃から逃げるのよ。","ENG":"I'll slice them open. Break free while I make an opening.","TWN":"我會先砍開一道縫隙，你們趁空檔脫離那傢伙的攻擊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"리드! 하지만…….","JPN":"リード！　でも……","ENG":"Read! But–","TWN":"里德！可是……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"모두가 살아 돌아갈 수 있는 해피 엔딩은 동화에나 나오는 일이란다.","JPN":"全員が生きて帰るハッピーエンドなんか、おとぎ話にしか存在しないわ。","ENG":"A happy ending where everyone survives only exists in fairy tales.","TWN":"只有童話裡才有能讓所有人平安回去的結局。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"현실은 최소한의 희생으로 최대한의 이득을 봐야 하는 일이 많지.","JPN":"現実は最小の犠牲で最大の利益を得なきゃならないことの方が多いもの。","ENG":"Reality demands the greatest gain at the smallest cost.","TWN":"現實往往是用最小的犧牲換取最大的收穫。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"그런 때가 온 거란다. 보니.","JPN":"今がそんな時だってことよ、ボニー。","ENG":"That's what this moment is, Bonny.","TWN":"而現在就是那個時候了，寶妮。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"선장 명령이다.","JPN":"船長命令だ。","ENG":"Captain's orders.","TWN":"這是船長的命令。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"너희는 전부 하선하도록.","JPN":"お前たち全員、下船するように。","ENG":"All of you, abandon ship.","TWN":"你們全都給我下船。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"선장. 분명히 얘기했던 것 같은데?","JPN":"船長、もう忘れたの？","ENG":"Captain. Didn't I make it clear?","TWN":"船長，我之前不是說過嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"너라는 존재가 고향에 어떤 의미를 지니고 있는지 입이 닳도록 얘기했잖니?","JPN":"故郷にとってあなたという存在がどんな意味を持つのか、あんなに何度も話したじゃない。","ENG":"I told you again and again what you mean to our homeland.","TWN":"我都費盡唇舌告訴你你對家鄉有多重要了吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그러니 더더욱 내가 있어서는 안 돼.","JPN":"だからこそ、私はいるべきではない。","ENG":"Which is exactly why I must not remain.","TWN":"所以我更不能留下。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"사람들은 스스로 내일의 태양을 맞이해야 의미가 있는 법.","JPN":"それぞれが自らの意志で明日の太陽を迎えなければ意味がないんだ。","ENG":"People must greet tomorrow's sun by their own strength.","TWN":"大家要自己迎接明天的太陽才有意義。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"전원, 인빈서블에서 하선해라.","JPN":"全員、インビンシブルから下船しろ。","ENG":"Everyone, disembark from the Invincible.","TWN":"所有人都從無敵號下船。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"내가 크라켄을 막겠어.","JPN":"私がクラーケンを止める。","ENG":"I'll hold off Kraken.","TWN":"我來阻止克拉肯。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"너희는 전부 다른 배로 옮겨타거라.","JPN":"あなたたち全員、他の船に移りなさい。","ENG":"All of you, move to the other ship.","TWN":"你們全都去別的船。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"이 촉수들은 내가 저지할 테니.","JPN":"この触手は私が引き止めるわ。","ENG":"I'll keep these tentacles at bay.","TWN":"我會阻止那些觸手。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"무리에요, 어머니!","JPN":"お母様、無理です！","ENG":"That's impossible, Mother!","TWN":"母親，這太勉強了！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어머니가 강하다는 건 알지만…….","JPN":"お母様が強いのはわかっていますが……","ENG":"I know you're strong, but still...","TWN":"我知道您很厲害，可是……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...*Sigh*","TWN":"……哈。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...*Sigh*","TWN":"……哈。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"이래서 선장을 기절시키자고 했잖니?","JPN":"だから船長を気絶させておこうって言ったのに。","ENG":"This is why I said we should knock the captain out first.","TWN":"所以我才說要敲昏船長啊？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"미안해, 선장.","JPN":"悪いね、船長。","ENG":"Sorry, Captain.","TWN":"抱歉了，船長。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"역시 우리는 선장의 명령을 따를 수 없어.","JPN":"やっぱり私たちは船長の命令には従えない。","ENG":"We can't obey your command.","TWN":"果然我們沒辦法遵從您的命令。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"선장이 선원을 버리지 못하는 것처럼, 선원도 선장을 버리지 못하는 법이니까.","JPN":"船長が船員を捨てられないのと同じく、船員も船長を捨てられないんだ。","ENG":"Just like a captain doesn't abandon the crew, the crew doesn't abandon the captain.","TWN":"就像船長不會丟下船員，我們也不會丟下船長。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"바보 같은 소리 하지 마, 앤 보니!","JPN":"バカなことを言うな、アン・ボニー！","ENG":"Don't be ridiculous, Anne Bonny!","TWN":"別說傻話了，安·寶妮！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"이건 선상 반란이야.","JPN":"これは船上反乱だ。","ENG":"This is mutiny.","TWN":"你知道這是叛變嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"여기서 사이 좋게 문어밥이 되고 싶지 않다면 얌전히 내 명령에 따라!","JPN":"仲良くタコの餌食になりたくなければ、大人しく命令に従え！","ENG":"If you don't want to end up octopus feed, follow my orders quietly!","TWN":"不想一起被煮成章魚炊飯的話就乖乖聽我指揮！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"미안하구나, 선장.","JPN":"ごめんなさいね、船長。","ENG":"Sorry, Captain.","TWN":"不好意思了，船長。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"해적단은 선장이 존재해야 유지되는 법이지.","JPN":"船長がいないと海賊団は成り立たないもの。","ENG":"A pirate crew exists only if its captain does too.","TWN":"要有船長才有海盜團。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"너는 언제나처럼 고향에 남아 사람들을 이끌어주렴.","JPN":"あなたはいつも通り故郷に残って、人々を導いて。","ENG":"You must stay alive and continue guiding the people of our homeland.","TWN":"您就像往常一樣留在家鄉引領大家吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"잠깐……!","JPN":"待て……！","ENG":"Wait...!","TWN":"等一下……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"나는 내 말에 토 다는 것을 별로 안 좋아한단다.","JPN":"私、口答えする子はあまり好きじゃないのよね。","ENG":"I don't take kindly to people talking back to me.","TWN":"我可不喜歡別人反駁我。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"넵. 서둘러 다른 배로 이동하겠습니다.","JPN":"はいっ。急いで他の船に移動します。","ENG":"Y-yes ma'am! Moving to the other ship right now!","TWN":"收到，我們會盡快轉移到其他船。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"아줌마도 여기서 탈출해.","JPN":"おばさんも逃げなよ。","ENG":"Auntie Mary, you're getting out of here too.","TWN":"阿姨妳也一起撤離。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"선체를 붙잡은 촉수들은 내가 어떻게든 처리해볼게.","JPN":"船体を捕まえてる触手は、あたしがなんとかしてみる。","ENG":"I'll deal with the tentacles hanging on the hull somehow.","TWN":"我會想辦法處理抓住船體的觸手。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"분명 내 말에 토다는 것을 안 좋아한다고 했을 텐데.","JPN":"口答えする子は好きじゃないって、言ったはずよ。","ENG":"I'm fairly sure I said I don't like people talking back to me.","TWN":"我不是說過我不喜歡別人反駁我嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"지금 그까짓 게 중요해?!","JPN":"そんなのはどうでもいいだろ！","ENG":"Is that really what matters right now?!","TWN":"現在都這種時候了，那很重要嗎？！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나는… 아줌마 덕분에 꿈이란걸 꾸게 되었어.","JPN":"あたしは……おばさんのおかげで夢を持つことができたんだ。","ENG":"I... I was able to dream because of you.","TWN":"我……因為阿姨才有了夢想。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"비록 길이 잘못되었다고 해도, 나는 어떻게든 나아갈 수 있었다고.","JPN":"間違った道だとしても、なんとか前に進むことができた。","ENG":"Even if my path was wrong, I still kept moving forward.","TWN":"就算沒有走在正確的路上，我也一直努力向前行。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그러니까… 이번엔 아줌마한테 보답할 차례야.","JPN":"だから……今度は、あたしがおばさんに恩返しする番。","ENG":"So now... it's my turn to repay you.","TWN":"所以……這次輪到我回報妳了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"아줌마한테는 가족이 있잖아.","JPN":"おばさんには家族がいるじゃない。","ENG":"You have a family to go back to.","TWN":"阿姨還有家人。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"가족이 없는 나는 아무래도… 아무래도 좋다고.","JPN":"家族がいないあたしは別に……どうなってもいいからさ。","ENG":"I don't have anyone... So it's fine.","TWN":"而我沒有……所以我無所謂。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...*Sigh*","TWN":"……哈。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"날 곤란하게 하는 건 모녀가 똑 닮았구나.","JPN":"親子揃って私を困らせてくれるわね。","ENG":"You're just like your mother. Trouble, the both of you.","TWN":"真是的，你們母女連讓人頭痛這點都很像呢。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그게 무슨 소리야, 아줌마?","JPN":"どういうこと？　おばさん。","ENG":"What do you mean by that?","TWN":"阿姨妳那是什麼意思？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"내가 이렇게 살아 있을 수 있는 건 다 네 엄마 덕이란다.","JPN":"私がこうして生きていられるのは、全部あなたのお母さんのおかげなの。","ENG":"I'm only alive thanks to your mother.","TWN":"我能活到現在，全都是因為妳媽媽啊。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"좋아. 이쪽의 촉수는 무사히 잘라냈어. 그쪽은 어떻니?","JPN":"よし、こっちの触手は無事切り落とせたわ。そっちはどう？","ENG":"Okay. I've severed the tentacle on my side. How's yours?","TWN":"好了！這邊的觸手處理完了。妳那邊呢？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L35_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"이쪽도 마찬가지야.","JPN":"こっちもだ。","ENG":"Same here.","TWN":"這邊也好了！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L36_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"이제 이 함선을 놈의 아가리에 들이박을 일만 남았네.","JPN":"あとはこの艦船をやつの口にぶち込むだけだな。","ENG":"Now all that's left is ramming this ship straight into its maw.","TWN":"只剩下把艦船直接撞進那怪物嘴裡了。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"누군가는 함교에 남아 조종해야 겠지만 말이다.","JPN":"誰かは艦橋に残って操縦する必要があるけどね。","ENG":"Someone will have to stay at the helm.","TWN":"只是得有人留下來操控艦船。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"무섭니, 보니?","JPN":"ボニー、怖い？","ENG":"Are you scared, Bonny?","TWN":"妳害怕嗎，寶妮？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"그럴리가.","JPN":"まさか。","ENG":"Of course not.","TWN":"怎麼可能。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"하지만… 혼자서 자랄 키이라가 걱정이네.","JPN":"でも……独りで育つことになるキーラが心配だな。","ENG":"But... I worry about Kiera growing up alone.","TWN":"但是……我擔心琪伊拉一個人長大。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"이곳으로 오기 얼마 전에 크루 갑판장을 만났단다.","JPN":"ここに来る少し前に、クルー甲板長に会ったの。","ENG":"I met the Crew Boatswain just before we set out.","TWN":"上船前我碰到克盧水手長。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"크루 갑판장? 그 고리타분한 해군 자식?","JPN":"クルー甲板長？　あの頭の硬い海軍野郎にか？","ENG":"The Crew Boatswain? That stiff-necked Navy brat?","TWN":"克盧水手長？那個老古板的海軍嗎？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"그 자식, 쓸데없이 꽉 막혀서는, 시도때도 없이 해적들을 잡으려고 하잖아.","JPN":"あの堅物め、隙あらば海賊を捕まえようとするじゃないか。","ENG":"He's always trying to arrest pirates for no reason!","TWN":"那傢伙就愛多管閒事，整天只會抓海盜。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"후훗, 그런 고리타분한 모습이 제법 귀엽지 않니?","JPN":"ふふっ、そんな融通の利かないところが結構可愛くない？","ENG":"Fufu... But don't you think that stiff-necked attitude is kind of cute?","TWN":"呵呵，那種古板的樣子不是挺可愛的嗎？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"내가 오랫동안 바다로 나갈 것 같다고 하니 대뜸, 돌아오면 하고 싶은 말이 있다더라.","JPN":"ちょっと長い航海になりそうって言ったら、その場で、帰ってきたら伝えたい言葉があるって言われたわ。","ENG":"When I said I'd be away at sea for a long time, he suddenly said he had something he wanted to tell me when I got back.","TWN":"我跟他說我可能會出海很久，他居然說等我回來有話想跟我說。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"……참 뜬금없는 녀석이네.","JPN":"……突然すぎるやつだな。","ENG":"...That's random.","TWN":"……真是莫名其妙的傢伙。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"후후, 그렇지?","JPN":"ふふ、そうね。","ENG":"Fufu, right?","TWN":"呵呵，對吧？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"어차피 그 대답은 못 들을 텐데 말이야.","JPN":"どうせその言葉の返事は聞けないのにね。","ENG":"Not that I'll ever hear an answer.","TWN":"反正我應該是聽不到那句話了。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"그러면 너는 이만 딸을 보러 가거라.","JPN":"じゃあ、あなたは娘のところに行ってあげて。","ENG":"Then you should go to your daughter.","TWN":"妳快去找妳女兒吧。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"부모 없는 자식으로 산다는 것이 얼마나 공허한 일인지, 우리는 잘 알잖니?","JPN":"親なくして育つ子の寂しさは、もうお互いよくわかっているじゃない。","ENG":"We both know too well how empty a childhood without parents can be.","TWN":"我們都知道沒有父母陪伴長大的孩子有多孤單。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"아니야. 메리.","JPN":"違うよ、メリー。","ENG":"No, Mary.","TWN":"不，瑪麗。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"응?","JPN":"え？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"생각보다 날 닮은 아이를 보는 일은 꽤 즐겁거든.","JPN":"自分に似た子を見守る日々は、思ったより楽しいんだ。","ENG":"Seeing a child who resembles me more than I expected is surprisingly wonderful.","TWN":"其實看到個性跟自己很像的孩子挺有趣的。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"친구로서, 난 네가 그 기분을 한번… 아니, 세 번 정도 느꼈으면 좋겠어.","JPN":"友達として、私はあんたにその気持を1回……いや、3回ぐらい味わってほしい。","ENG":"As a friend, I want you to feel that joy at least once– No, three times if you can.","TWN":"身為朋友，我希望妳也能體會一次……不，體驗三次。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"그게 무슨 소…….","JPN":"それどういう……","ENG":"What are you–","TWN":"那是什麼意思……"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"절벽에서 바라보는 일출은 아름다웠다.","JPN":"崖っぷちで眺める日の出は美しかった。","ENG":"The sunset sky was beautiful.","TWN":"在懸崖看見的日出美得讓人窒息。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"마하 섬 절벽에 옹기종기 모여 그것을 보고 있노라면.","JPN":"マッハ島の崖っぷちに集まってそれを眺めていると。","ENG":"Gathered on the cliff of Macha Island, watching it together–","TWN":"大家聚在瑪查島的懸崖一起看著那景象時，"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"그래. 나는 내일도 이것을 보기 위해 살아야겠다.","JPN":"ああ、明日もこれを見るために生きないと。","ENG":"Yes. I wanted to live just to see it again tomorrow.","TWN":"我總會想著為了見到明天的日出，"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"그런 생각을 하고는 했다.","JPN":"そう思ったりした。","ENG":"That's what I used to think.","TWN":"我得繼續活著。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"상부 갑판 위에서 떨어지며 바라보는 노을은.","JPN":"上部の甲板から落ちていきながら見た夕暮れは。","ENG":"Falling from the upper deck, staring at that same sunset.","TWN":"而在上層甲板墜落時看到的那抹晚霞，"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 그 노을을 등지고 환하게 웃던 그 아이는.","JPN":"その夕暮れを背に笑っていたあの子は。","ENG":"And the girl who smiled so brightly with that sunset at her back...","TWN":"還有背對晚霞，對我露出燦笑的那個孩子"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"그 무엇보다 아름다웠다.","JPN":"他のどんなものよりも美しくて。","ENG":"Was more beautiful than anything.","TWN":"比什麼都美麗。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기 때문에 나는…….","JPN":"だから私は……","ENG":"That's why I...","TWN":"所以我……"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"내일이 다시는 오지 않게 해달라 빌고 싶었다.","JPN":"二度と明日になんかならないよう祈りたくなった。","ENG":"I felt like wishing tomorrow would never come.","TWN":"希望再也不要有明天。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇구나… 엄마는…….","JPN":"そうか……お母さんは……","ENG":"So that's why... Mom...","TWN":"我明白了……媽媽她……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"이제서야 이야기해서 미안하구나.","JPN":"ずっと黙っていてごめんなさい。","ENG":"I told you, didn't I? I'm sorry it took so long to say it.","TWN":"對不起，我現在才告訴妳。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"……10년 전의 검은 범람만 아니었다면 나는 너를 끝까지 책임질 생각이었단다.","JPN":"……10年前の黒い氾濫さえなければ、私は最後まであなたの面倒を見るつもりだったの。","ENG":"...If the Black Flood ten years ago hadn't happened, Kiera, I would have raised you myself.","TWN":"……要不是10年前那場黑色洪災，我其實想過要負起責任把妳養大。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"네 엄마에 대한 것, 그리고 해적이란 뭔지, 어떻게 하면 사람들과 잘 지낼 수 있는지.","JPN":"あなたのお母さんのこと、海賊とは何かということ、人との付き合い方を教えて……","ENG":"About your mother, about what it means to be a pirate, about how to live with others.","TWN":"我想告訴妳關於妳母親的一切、什麼是海盜、要怎麼與人相處。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"우리 딸들과 함께 너희 엄마의 이야기를 하며 해적단 생활이 얼마나 재밌었는지…….","JPN":"娘たちと一緒にあなたのお母さんの話をして、海賊団の生活がどれほど楽しいものだったのかも……","ENG":"I would've told those stories while raising you alongside my girls, sharing how fun pirate life really was...","TWN":"和我女兒們一起聊著妳媽媽的故事，讓妳也知道我們海盜團的生活有多快樂……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"……미안하구나.","JPN":"……ごめんなさい。","ENG":"...I'm sorry.","TWN":"……對不起。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"우리는 너무나 나약해서… 그저 숨어 있을 수밖에 없었단다.","JPN":"私たちはただ身を潜めることしかできなかった……あまりにも弱かったから。","ENG":"We were weak that... hiding was all we could do.","TWN":"我們太弱小……只敢躲起來。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"미래의 아이들마저 상처 입을까 봐 뒤에서 바라볼 수밖에 없을 만큼.","JPN":"未来の子どもたちを傷つけることが怖くて、後ろでただ見ていることしかできないほど。","ENG":"So weak that we could only watch from behind, afraid the children of the future might be hurt.","TWN":"我們怕連未來的孩子都會受傷，只能在背後默默看著。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……지금은 그런 사과를 받을 때가 아니야.","JPN":"……今はそんな謝罪を受けている場合じゃない。","ENG":"...This isn't the time for apologies.","TWN":"……現在不是道歉的時候。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"난 크라켄을 막고… 아줌마를 구할 거야.","JPN":"あたしはクラーケンを食い止めて……おばさんを助ける。","ENG":"I'm going to stop Kraken... and I'm going to save you.","TWN":"我會阻擋克拉肯……救出阿姨。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그 다음에… 그 다음에는 꼭…….","JPN":"だから、その後……その後、絶対……","ENG":"And after that... after all that...","TWN":"然後……在那之後一定……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"아줌마랑 엄마가 어떻게 해적 생활을 했는지 알려줘.","JPN":"おばさんとお母さんの海賊生活について、聞かせて。","ENG":"You'll tell me how you and Mom lived as pirates.","TWN":"要告訴我妳跟媽媽以前的海盜生活到底有多精彩。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"……그래.","JPN":"……ええ。","ENG":"...Okay.","TWN":"……好。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"약속하마.","JPN":"約束するわ。","ENG":"I promise.","TWN":"我答應妳。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"탈리네 아줌마. 당신이 한 말, 정말 사실이야?","JPN":"タリーのお母さん。さっきの話は本当なのか？","ENG":"Tallie's mom, what you said. Is it really true?","TWN":"塔莉的阿姨。妳剛說的真的是事實嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그렇단다. 에이버리의 보물.","JPN":"そうよ、エイバリーの宝物。","ENG":"It is. Avery's treasure.","TWN":"對，那就是艾維利的寶物。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"물어보고 싶은 게 있어.","JPN":"聞きたいことがある。","ENG":"I want to ask something.","TWN":"我想問一個問題。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아버지가 원망스럽니?","JPN":"お父さんを恨んでる？","ENG":"Are you angry at your father?","TWN":"妳恨妳父親嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그닥.","JPN":"別に。","ENG":"Not really.","TWN":"還好吧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"요즘 같은 시대에 부모와 자식이 헤어지는 건 프론트 베이에선 흔한 일이니까.","JPN":"今の時代、親子が離れ離れになることぐらい、フロントベイでは珍しいことじゃないし。","ENG":"Parents and children being separated is common in Front Bay these days.","TWN":"在這年代，妻離子散在前灣早就不是什麼新鮮事了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아버지를 만난다면 이 말을 전달해 줄 수 있어?","JPN":"お父さんに会ったら伝えてほしいことがあるんだけど。","ENG":"If you ever meet him, can you tell him something?","TWN":"如果妳遇到他，可以幫我帶句話嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"뭐든지.","JPN":"もちろん。","ENG":"Sure.","TWN":"沒問題。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"이럴 때 쓰라고 있는 게 인맥과 돈 아니겠니?","JPN":"金と人脈はこういう時使うものよ。","ENG":"Isn't this exactly what money and connections are for?","TWN":"這種時候能用的就是人脈跟錢吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"……어릴 때 먹었던 생선들, 정말 맛있었다고.","JPN":"……子どもの頃食べた魚、本当においしかったって。","ENG":"...That the fish I ate as a kid... were really good.","TWN":"……就說小時候吃過的魚真的很好吃。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그리고… 아버지의 칼, 회 써는 데 쓰니까 날이 아주 잘 들어서 좋다고도 전해줘.","JPN":"あと……お父さんのナイフ、切れ味がよくて刺身を切る時重宝してるって伝えてくれ。","ENG":"And... tell him his knife works great for slicing sashimi.","TWN":"還有……父親的那把刀，用來切生魚片超好用。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후훗, 그 아비에 그 딸이로구나.","JPN":"ふふっ、子は親に似るというけど、本当ね。","ENG":"Fufu, you really are your father's daughter.","TWN":"呵呵，真不愧是父女。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"벨라미. 도시 쪽은 어떻게 되어가고 있니?","JPN":"ベラミー、都市の方はどう？","ENG":"Bellamy, how are things on the city's side?","TWN":"貝拉米，城市那邊怎麼樣了？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"쉽지 않은 작업이라 들었다마는.","JPN":"簡単ではない作業だと聞いたけれど。","ENG":"I heard it wasn't easy.","TWN":"聽說作業不容易。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"크루 가문의 도움으로 여러 차원 함선을 확보할 수 있어 다행이었습니다.","JPN":"幸い、クルー家の協力もあり、次元艦船を多数確保できましたので。","ENG":"Thanks to the Crew family, we managed to secure several dimensional ships.","TWN":"但多虧克盧家，我們順利取得不少跨次元艦船。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L25_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"덕분에 시민들을 우선 피신시킬 수 있었어요.","JPN":"市民たちを優先的に避難させることができました。","ENG":"We were able to evacuate the citizens first.","TWN":"因此才能先疏散市民。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"선로전환기도 무사히 전달받아 곧 실용 단계에 오를 예정입니다.","JPN":"線路転換器も無事に受け取り、もうすぐ実用段階に入る予定です。","ENG":"We also received the Track Switcher safely, and it'll reach operational stage soon.","TWN":"線路轉換器也順利送達了，很快就能正式啟用。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"이것도 다 크루 가문에서 팩토리 쉽이 착륙할 자리를 잡아줬기 때문에 가능한 일이었죠.","JPN":"これもすべて、クルー家からファクトリーシップが着陸する場所を設けていただいたおかげです。","ENG":"All thanks to the Crew family preparing a landing zone for the Factory Ship.","TWN":"還有也是克盧家幫忙找盜能讓工廠艦安全降落的地點。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"다행이구나. 나와 그이가 도와줄 수 있는 건 가문의 재력을 쏟아 붙는 것밖에 없었으니.","JPN":"よかったわ。私と夫ができることなんて、家の財力を注ぎ込むことぐらいしかないもの。","ENG":"That's good. All we could offer was our family's wealth and support.","TWN":"真是太好了。我跟那個人能做的，就是貢獻家族的財力。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님께서도 무척이나 감사해하고 있습니다.","JPN":"シニア様もとても感謝しています。","ENG":"The Senior is deeply grateful as well.","TWN":"Senior也非常感謝妳。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"흥, 도시라는 배를 몰고 있는 선장이라면 그런 것도 당연하게 여겨야 하거늘.","JPN":"ふん。都市という船の舵を握っている船長なら、そんなのにいちいち感謝しなくてもいいのに。","ENG":"Hmph. A captain steering a ship called a city should take that for granted.","TWN":"哼，坐在城市這艘大船的船長，本來就該把人民的事視為理所當然。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"뭐… 그게 많은 사람이 선장을 따랐던 이유이기도 했지만.","JPN":"まあ、そんな人だから多くの人に慕われたわけだけど。","ENG":"Still, that's why so many followed him.","TWN":"不過……那也是大家追隨他的原因吧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"바, 바다쪽에 고밀도 침식파 포착.","JPN":"う、海のほうから高密度の侵食波を捕捉。","ENG":"D-detecting a high-density Corruption ray offshore.","TWN":"海面偵測到高密度侵蝕波。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"식별 결과… 크라켄의 본체입니다.","JPN":"識別結果……クラーケンの本体です。","ENG":"Identification complete... It's Kraken's real form.","TWN":"辨識結果……是克拉肯本體！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"대균열을 지키기 위해 직접 나선 모양이군.","JPN":"大亀裂を守るために、直接出向いたようね。","ENG":"So it finally came out to guard the Grand Dimension Crevice itself.","TWN":"它好像為了守護大峽谷親自現身了呢。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그렇다면… 이렇게 있을 때가 아니겠구나.","JPN":"なら……こうしている場合じゃないわ。","ENG":"Then... this isn't the time to sit around.","TWN":"那我們……不能再浪費時間了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"사냥감에게 사냥 당하는 것만큼 꼴 사나운 건 없을 테니.","JPN":"獲物に狩られる狩人ほど、みっともないものもないしね。","ENG":"Nothing's more disgraceful than letting your prey turn the tables on you.","TWN":"沒有被獵物反過來狩獵更丟臉的事了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그럼 우리가 해야 할 일은…….","JPN":"じゃああたしたちがやることは……","ENG":"Then what we need to do is...","TWN":"所以我們該做的就是……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"크라켄을 끝장내고 검은 범람을 종식시킨다. 맞지?","JPN":"クラーケンをぶっ倒して、黒い氾濫を終わらせる。だろ？","ENG":"We're going to end Kraken and stop the Black Flood. Right?","TWN":"解決克拉肯並終結黑色洪災，對吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후후, 이제 어엿한 해적다운 대답을 내뱉는구나.","JPN":"ふふ、一人前に海賊らしいこと言うようになったわね。","ENG":"Fufu, that's the kind of answer a true pirate gives.","TWN":"呵呵，妳現在倒像個真海盜了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"슬슬… 이 자리를 넘겨줘야 할지도 모르겠어.","JPN":"そろそろ……この座を譲る時が来たのかも。","ENG":"I suppose... it may be time for me to pass the torch.","TWN":"看來……差不多該把這個位置讓給你們了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"응…? 그게 무슨 말이야?","JPN":"うん……？　どういうことだ？","ENG":"Huh...? What do you mean?","TWN":"嗯……？那是什麼意思？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아무것도 아니란다.","JPN":"何でもないわ。","ENG":"Nothing.","TWN":"沒什麼。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"곧 있으면 알게 될 테니 구태여 지금 얘기해줄 필요는 없겠지.","JPN":"すぐにわかるでしょうし、わざわざ今話す必要はないもの。","ENG":"You'll find out soon enough. No need to explain it now.","TWN":"你們很快就會知道了，沒必要現在說。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"무슨 말인지는 모르겠지만… 알겠어.","JPN":"どういう意味だかさっぱりだが……わかった。","ENG":"I don't get it... but fine.","TWN":"雖然不知道妳在說什麼……但好吧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"어서 크라켄을 해치우고 마하 섬의 일출을 모두에게 보여주자고.","JPN":"早くクラーケンを倒して、みんなにマッハ島の日の出を見せようぜ。","ENG":"Let's take down Kraken and show everyone the sunrise of Macha Island.","TWN":"我們把克拉肯打倒，再讓所有人都能再次見到瑪查島的日出。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나도… 그 일출을 꼭 보고싶으니까.","JPN":"あたしも……その日の出、是非とも見たいしな。","ENG":"Because... I also want to see that sunrise, no matter what.","TWN":"因為我也……想再次看到那道日出。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그런 다짐도 제법 해적다워서 마음에 들었다.","JPN":"その覚悟も、海賊らしくて気に入ったわ。","ENG":"That resolve suits you. Quite pirate-like.","TWN":"有這樣的決心很像海盜，我很滿意。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"모두, 무기를 들고 바다에 맞서거라.","JPN":"みんな、武器を構えて海に立ち向かいなさい。","ENG":"Everyone, take up your weapons and face the sea!","TWN":"大家拿起武器，向大海宣戰吧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_BOSS_KRAKEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"진정한 사냥꾼은 사냥감을 구분하지 않는 법이니.","JPN":"狩りは獲物に左右されないものだからね。","ENG":"One who lives by the hunt doesn't get to be picky.","TWN":"真正的獵人，不會挑獵物。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_BOSS_KRAKEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};